354: 	int address_of(const Address &p_address) {
355: 		switch (p_address.mode) {
356: 			case Address::SELF:
357: 				return GDScriptFunction::ADDR_SELF;
358: 			case Address::CLASS:
359: 				return GDScriptFunction::ADDR_CLASS;
360: 			case Address::MEMBER:
361: 				return p_address.address | (GDScriptFunction::ADDR_TYPE_MEMBER << GDScriptFunction::ADDR_BITS);
362: 			case Address::CONSTANT:
363: 				return p_address.address | (GDScriptFunction::ADDR_TYPE_CONSTANT << GDScriptFunction::ADDR_BITS);
364: 			case Address::LOCAL_VARIABLE:
365: 			case Address::FUNCTION_PARAMETER:
366: 				return p_address.address | (GDScriptFunction::ADDR_TYPE_STACK << GDScriptFunction::ADDR_BITS);
367: 			case Address::TEMPORARY:
368: 				temporaries.write[p_address.address].bytecode_indices.push_back(opcodes.size());
369: 				return -1;
370: 			case Address::NIL:
371: 				return GDScriptFunction::ADDR_NIL;
372: 		}
373: 		return -1; // Unreachable.
374: 	}
