60: static String _get_var_type(const Variant *p_var) {
61: 	String basestr;
62: 
63: 	if (p_var->get_type() == Variant::OBJECT) {
64: 		bool was_freed;
65: 		Object *bobj = p_var->get_validated_object_with_check(was_freed);
66: 		if (!bobj) {
67: 			if (was_freed) {
68: 				basestr = "previously freed";
69: 			} else {
70: 				basestr = "null instance";
71: 			}
72: 		} else {
73: 			if (bobj->is_class_ptr(GDScriptNativeClass::get_class_ptr_static())) {
74: 				basestr = Object::cast_to<GDScriptNativeClass>(bobj)->get_name();
75: 			} else {
76: 				basestr = bobj->get_class();
77: 				if (bobj->get_script_instance()) {
78: 					basestr += " (" + GDScript::debug_get_script_name(bobj->get_script_instance()->get_script()) + ")";
79: 				}
80: 			}
81: 		}
82: 
83: 	} else {
84: 		if (p_var->get_type() == Variant::ARRAY) {
85: 			basestr = "Array";
86: 			const Array *p_array = VariantInternal::get_array(p_var);
87: 			Variant::Type builtin_type = (Variant::Type)p_array->get_typed_builtin();
88: 			if (builtin_type != Variant::NIL) {
89: 				basestr += "[" + _get_element_type(builtin_type, p_array->get_typed_class_name(), p_array->get_typed_script()) + "]";
90: 			}
91: 		} else {
92: 			basestr = Variant::get_type_name(p_var->get_type());
93: 		}
94: 	}
95: 
96: 	return basestr;
97: }
