541: 			if (argument_types[i].is_type(*p_args[i], false)) {
542: 				memnew_placement(&stack[i + 3], Variant(*p_args[i]));
543: 				continue;
544: 			}
545: 			if (!argument_types[i].is_type(*p_args[i], true)) {
546: 				r_err.error = Callable::CallError::CALL_ERROR_INVALID_ARGUMENT;
547: 				r_err.argument = i;
548: 				r_err.expected = argument_types[i].builtin_type;
549: 				call_depth--;
