562: 						r_err.argument = i;
563: 						r_err.expected = argument_types[i].builtin_type;
564: 						call_depth--;
565: 						return _get_default_variant_for_data_type(return_type);
566: 					}
567: 					memnew_placement(&stack[i + 3], Variant(variant));
568: 				}
569: 			} else {
570: 				memnew_placement(&stack[i + 3], Variant(*p_args[i]));
571: 			}
572: 		}
573: 		for (int i = p_argcount + 3; i < _stack_size; i++) {
